import fs from "node:fs";
import path from "node:path";
import type {
  BatchOp,
  Bytes,
  IterOptions,
  KvPair,
  Storage,
} from "@unlink-xyz/core";
import { validateKey } from "@unlink-xyz/core";
import Database from "better-sqlite3";

export type SqliteStorageOptions = {
  /** Full path to the .db file */
  path: string;
};

export function createSqliteStorage(opts: SqliteStorageOptions): Storage {
  let db: Database.Database | null = null;
  let stmtGet: Database.Statement;
  let stmtPut: Database.Statement;
  let stmtDel: Database.Statement;
  let stmtGetSchema: Database.Statement;
  let stmtUpsertSchema: Database.Statement;

  return {
    async open() {
      const dir = path.dirname(opts.path);
      fs.mkdirSync(dir, { recursive: true });

      db = new Database(opts.path);
      db.pragma("journal_mode = WAL");
      db.pragma("busy_timeout = 5000");
      db.exec(`
        CREATE TABLE IF NOT EXISTS kv (key TEXT PRIMARY KEY, value BLOB NOT NULL);
        CREATE TABLE IF NOT EXISTS meta (key TEXT PRIMARY KEY, value INTEGER NOT NULL);
      `);

      stmtGet = db.prepare("SELECT value FROM kv WHERE key = ?");
      stmtPut = db.prepare(
        "INSERT OR REPLACE INTO kv (key, value) VALUES (?, ?)",
      );
      stmtDel = db.prepare("DELETE FROM kv WHERE key = ?");
      stmtGetSchema = db.prepare(
        "SELECT value FROM meta WHERE key = 'schema_version'",
      );
      stmtUpsertSchema = db.prepare(
        "INSERT OR REPLACE INTO meta (key, value) VALUES ('schema_version', ?)",
      );
    },

    async get(key: string): Promise<Bytes | null> {
      validateKey(key);
      const row = stmtGet.get(key) as { value: Buffer } | undefined;
      return row ? new Uint8Array(row.value) : null;
    },

    async put(key: string, value: Bytes): Promise<void> {
      validateKey(key);
      stmtPut.run(key, Buffer.from(value));
    },

    async delete(key: string): Promise<void> {
      validateKey(key);
      stmtDel.run(key);
    },

    async batch(ops: BatchOp[]): Promise<void> {
      const runBatch = db!.transaction(() => {
        for (const op of ops) {
          if (op.put) {
            const [k, v] = op.put;
            validateKey(k);
            stmtPut.run(k, Buffer.from(v));
          }
          if (op.del) {
            validateKey(op.del);
            stmtDel.run(op.del);
          }
        }
      });
      runBatch();
    },

    async iter(o: IterOptions = {}): Promise<KvPair[]> {
      if (o.start && o.end && o.start > o.end) {
        throw new Error("iter start bound must not exceed end bound");
      }

      const conditions: string[] = [];
      const params: (string | number)[] = [];

      if (o.prefix) {
        // Escape SQL LIKE wildcards in the prefix
        const escaped = o.prefix.replace(/[%_\\]/g, "\\$&");
        conditions.push("key LIKE ? ESCAPE '\\'");
        params.push(escaped + "%");
      }
      if (o.start) {
        conditions.push("key >= ?");
        params.push(o.start);
      }
      if (o.end) {
        conditions.push("key <= ?");
        params.push(o.end);
      }

      let sql = "SELECT key, value FROM kv";
      if (conditions.length > 0) {
        sql += " WHERE " + conditions.join(" AND ");
      }
      sql += o.reverse ? " ORDER BY key DESC" : " ORDER BY key ASC";
      if (o.limit != null) {
        sql += " LIMIT ?";
        params.push(o.limit);
      }

      const rows = db!.prepare(sql).all(...params) as Array<{
        key: string;
        value: Buffer;
      }>;

      return rows.map((row) => ({
        key: row.key,
        value: new Uint8Array(row.value),
      }));
    },

    async count(prefix?: string): Promise<number> {
      let sql = "SELECT COUNT(*) as cnt FROM kv";
      const params: string[] = [];
      if (prefix) {
        const escaped = prefix.replace(/[%_\\]/g, "\\$&");
        sql += " WHERE key LIKE ? ESCAPE '\\'";
        params.push(escaped + "%");
      }
      const row = db!.prepare(sql).get(...params) as { cnt: number };
      return row.cnt;
    },

    async getSchemaVersion(): Promise<number> {
      const row = stmtGetSchema.get() as { value: number } | undefined;
      return row?.value ?? 0;
    },

    async setSchemaVersion(v: number): Promise<void> {
      stmtUpsertSchema.run(v);
    },
  };
}
